import { Request, Response, NextFunction } from 'express';
import { UserService } from './user.service';
import { UserDto } from './user.dto';
import { validateUser } from './user.validator';
import { AppError } from '../../utils/app-error';
import logger from '../../config/logger';

export class UserController {
  private userService: UserService;

  constructor() {
    this.userService = new UserService();
  }

  public async register(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const validationResult = validateUser(req.body);
      if (!validationResult.success) {
        logger.error(`Validation failed: ${validationResult.error}`, { requestId: req.id });
        throw new AppError('E400', 'Invalid user data.');
      }

      const userDto = new UserDto(validationResult.data);
      const user = await this.userService.register(userDto);

      res.status(201).json({
        success: true,
        data: user,
        meta: {
          requestId: req.id,
          timestamp: new Date(),
          version: 'v1',
        },
      });
    } catch (err) {
      next(err);
    }
  }
}

import { UserRepository } from './user.repository';
import { UserDto } from './user.dto';

export class UserService {
  private userRepository: UserRepository;

  constructor() {
    this.userRepository = new UserRepository();
  }

  public async register(userDto: UserDto): Promise<UserDto> {
    // Implement business logic here
    const user = await this.userRepository.create(userDto);
    return new UserDto(user);
  }
}

import { UserModel } from './user.model';
import { UserDto } from './user.dto';

export class UserRepository {
  public async create(userDto: UserDto): Promise<UserDto> {
    const user = await UserModel.create(userDto);
    return new UserDto(user);
  }
  // Additional CRUD operations
}

import mongoose, { Schema, Document } from 'mongoose';

const UserSchema: Schema = new Schema({
  username: { type: String, required: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now },
});

export interface IUser extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

export const UserModel = mongoose.model<IUser>('User', UserSchema);

export class UserDto {
  public username: string;
  public email: string;
  public passwordHash?: string;
  public createdAt?: Date;

  constructor(data: { username: string; email: string; passwordHash?: string; createdAt?: Date }) {
    this.username = data.username;
    this.email = data.email;
    this.passwordHash = data.passwordHash;
    this.createdAt = data.createdAt;
  }
}

import { z } from 'zod';

const UserSchema = z.object({
  username: z.string().min(3).max(50),
  password: z.string().min(8),
  email: z.string().email(),
});

export const validateUser = (data: any) => {
  return UserSchema.safeParse(data);
};

import { z } from 'zod';

const envSchema = z.object({
  PORT: z.string().min(2),
  JWT_SECRET: z.string().min(20),
  MONGO_URI: z.string().url(),
  RATE_LIMIT_MAX: z.number().min(1),
  RATE_LIMIT_WINDOW: z.string().min(2),
});

const env = envSchema.safeParse(process.env);
if (!env.success) {
  throw new Error(`Environment validation error: ${JSON.stringify(env.error.issues)}`);
}

export default env.data;

import winston from 'winston';

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.Console(),
    // Additional transports can be added here
  ],
});

export default logger;
